-- 0009_wiki.sql
-- /wiki — 魔方术语表。Seed 数据 (713 条) 从 glossary.txt → glossary.json 一次性导入。
-- 协作模型:
--   - source='seed' / owner_wca_id NULL = 不可改 (admin 例外)
--   - source='user' = owner 可改,其他人只能在下面 wiki_additions 增补
--   - 软删 (deleted_at) 替代 DELETE,审计 + 抗滥用

CREATE TABLE wiki_terms (
  id           BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  letter       CHAR(1) NOT NULL,                          -- '#' 或 'A'..'Z'
  position     INTEGER NOT NULL,                          -- 同 letter 内排序键
  head         TEXT NOT NULL,                             -- 第一行: term + 可选 (English) + 可选 中文
  body         TEXT NOT NULL DEFAULT '',                  -- 余下行,blank-line 分段
  source       TEXT NOT NULL DEFAULT 'user',              -- 'seed' | 'user'
  owner_wca_id TEXT,                                      -- NULL 表 seed,否则创建者 WCA ID
  owner_name   TEXT NOT NULL DEFAULT '',
  created_at   TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  updated_at   TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  deleted_at   TIMESTAMPTZ
);
CREATE INDEX idx_wiki_terms_letter_pos ON wiki_terms (letter, position) WHERE deleted_at IS NULL;
CREATE INDEX idx_wiki_terms_owner     ON wiki_terms (owner_wca_id) WHERE owner_wca_id IS NOT NULL;

CREATE TABLE wiki_additions (
  id           BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  term_id      BIGINT  NOT NULL REFERENCES wiki_terms(id) ON DELETE CASCADE,
  body         TEXT    NOT NULL,
  owner_wca_id TEXT    NOT NULL,
  owner_name   TEXT    NOT NULL DEFAULT '',
  created_at   TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  updated_at   TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  deleted_at   TIMESTAMPTZ
);
CREATE INDEX idx_wiki_additions_term ON wiki_additions (term_id, created_at) WHERE deleted_at IS NULL;

